const contacts = $input.first().json.data || $input.first().json || [];
const ids = [];
for (const c of (Array.isArray(contacts) ? contacts : [contacts])) {
  const id = c.id || (c.custom_fields || {}).dos_number || `email:${c.email}`;
  ids.push(id);
}
return [{ json: { entityIds: ids, count: ids.length } }];
